import { useState } from 'react';
import FixturesArray from '../../data/fixtures'
import ResultsRow from './resultsrow'
import AddFixture from '../fixture/fixture';

const ResultsGrid = () => {

    // useState is a hook. Must be first line of the function. 
    // useState(xxx) - xxx is the original collection
    // [fixtures,...] - fixtures is the current copy of it. This will get updated by using setFixture
    // [..., setFixture] - is a function used to update the fixtures array.
    const [fixtures, setFixture] = useState(FixturesArray);   
    return(
        <>    
        <div className="row">
            <div className='col-1'></div>
            <div className='col-10'>
                <table className="table table-hover table-condensed table-responsive">
                    <thead>
                        <tr>
                            <th>Date</th>
                            <th></th>
                            <th>Home Team</th>
                            <th></th>
                            <th></th>
                            <th>Away Team</th>                            
                            <th>Pts</th>
                        </tr>
                    </thead>
                    <tbody>
                        {fixtures.map(f => <ResultsRow key={f.id} fixture={f} viewFixture={viewFixture}/>)}
                    </tbody>
                </table>                          
            </div>
        </div>        
        <AddFixture currentFixtures={fixtures} setFixtureIntoArray={setFixture}/>
        </>
    );
}
export default ResultsGrid;


